const SafeImage = ({ src, fallback, alt, className }) => {
  const [imgSrc, setImgSrc] = useState(src);

  return (
    <img
      src={imgSrc}
      alt={alt}
      className={className}
      referrerPolicy="no-referrer"
      onError={() => setImgSrc(fallback)}
    />
  );
};

const HeroSection = () => {
